 if(id==='resources') return head(t('Care & track','Soin & suivi'),t('Resources','Ressources'),t('Go deeper when you\'re ready.','Aller plus loin quand vous êtes prête.'))+'<p class="txt muted" style="margin-bottom:18px;max-width:34em">'+t('This studio is your foundation. When you want to master one area completely, these companion guides take you further.','Ce studio est votre base. Pour maîtriser un domaine, ces guides vont plus loin.')+'</p><div class="grid g3" id="res"></div>'+comp('tip','✦  '+t('A note','Une note'),t('Recommendations are here to help, not to rush you. Master the basics here first.','Les recommandations aident, sans précipiter. Maîtrisez d\'abord les bases ici.'))+backupCard();
